function extractFromAgGrid(root) {
    // ag-Grid often renders rows as divs; we do a best-effort extraction for visible rows only.
    const rows = [];
    const headerCells = root.querySelectorAll('.ag-header-cell-text');
    const header = [...headerCells].map(x => x.textContent.trim()).filter(Boolean);
    if (header.length) rows.push(header);

    const rowEls = root.querySelectorAll('.ag-center-cols-container .ag-row');
    rowEls.forEach(row => {
      const cols = row.querySelectorAll('.ag-cell');
      const r = [...cols].map(c => c.textContent.trim());
      if (r.length) rows.push(r);
    });
    return rows;
  }

