.btn{background:var(--accent);color:var(--accentInk);border:2px solid #0849ad;border-radius:10px;
  padding:12px 14px;cursor:pointer;min-height:48px;font-weight:900}
.btn.secondary{background:#fff;color:var(--ink);border-color:var(--border)}
.btn:focus,.tile:focus,input:focus,select:focus{outline:3px solid var(--focus);outline-offset:2px}
.grid{display:grid;grid-template-columns:360px 1fr;gap:14px}
@media (max-width: 980px){ .grid{grid-template-columns:1fr;} }
.card{background:var(--card);border:2px solid var(--border);border-radius:14px;padding:14px}
.small{font-size:.95rem;color:var(--muted)}
.row{display:flex;gap:10px;flex-wrap:wrap;align-items:center}
input,select{font-size:1rem;padding:10px 12px;border-radius:12px;border:2px solid var(--border);background:#fff;font-weight:800}
.tiles{display:grid;gap:10px;grid-template-columns:1fr}
.tile{display:block;width:100%;text-align:left;border:2px solid var(--border);background:#fff;border-radius:14px;padding:12px 12px;cursor:pointer}
.tile h3{margin:0;font-size:1.02rem}
.tags{margin-top:8px;display:flex;gap:6px;flex-wrap:wrap}
.tag{display:inline-block;background:#eef3ff;border:1px solid #bcd0ff;color:#0b2a66;border-radius:999px;padding:3px 10px;font-size:.85rem;font-weight:900}
.tile[data-active="1"]{outline:3px solid var(--accent)}
.tile[data-done="1"]{border-color:var(--good);background:#e8f5ec}

