      "forbid_repeated_failures": true,
      "forbid_sweep_inflation_without_gain": true,
      "force_runtime_heuristic_upgrade_on_failure": true,
      "require_experiential_update_each_cycle": true
    },
    "global_invariants": {
      "max_meta_reflection_passes": 5,
      "no_autonomous_execution": true,
      "require_evidence_chain_for_all_engines": true
    },
