      "require_evidence_logging": true,
      "require_teks_alignment": true
    },
    "mtss_invariants": {
      "explanation_first_required": true,
      "must_expose_thresholds": true,
      "must_tie_risk_to_concepts":

"base_engines/Kernel.json": "{
  "body": {
    "description": "The Kernel is the orchestration core of MetaBlooms OS vOmega21. It owns lifecycle, invariants, dispatch, reflection, error handling, evidence emission, and cross-module contract enforcement.",
    "dispatch": {
      "routes": {
        "ArticleEngine": "Engines.ArticleEngine.execute",
        "BridgeEngine_v2": "Engines.BridgeEngine_v2.invoke",
        "LearningSystem_v2": "Engines.LearningSystem_v2.execute",
        "MTSS": "Engines.MTSS.execute",
        "SandcrawlerEngine": "Engines.SandcrawlerEngine.execute",
        "TeachingEngine": "Engines.TeachingEngine.execute"
      },
      "rules": {
        "log_dispatch_to_evidence_chain": true,
        "require_explicit_engine_selection": true,
        "validate_task_packet_schema": true
      }
    },
    "entrypoints": {
      "dispatch_engine": "Kernel.dispatch_engine",
      "execute_pipeline": "Kernel.execute_pipeline",
      "export_results": "Kernel.export_results",
      "invoke": "Kernel.invoke",
      "run_meta_reflection": "Kernel.run_meta_reflection",
      "run_preflight": "Kernel.run_preflight"
    },
    "error_handling": {
      "classes": [
        "configuration_error",
        "missing_module_error",
        "contract_binding_error",

